32: /**
33:  * The JSSE provider.
34:  */
35: public class SunJSSE extends java.security.Provider {
36: 
37:     @java.io.Serial
38:     private static final long serialVersionUID = 3231825739635378733L;
39: 
40:     private static final String info = "Sun JSSE provider" +
41:         "(PKCS12, SunX509/PKIX key/trust factories, " +
42:         "SSLv3/TLSv1/TLSv1.1/TLSv1.2/TLSv1.3/DTLSv1.0/DTLSv1.2)";
