44:     public SunJSSE() {
45:         super("SunJSSE", PROVIDER_VER, info);
46:         registerAlgorithms();
47:     }
48: 
49:     private void ps(String type, String algo, String cn,
50:             List<String> a, HashMap<String, String> attrs) {
51:         putService(new Provider.Service(this, type, algo, cn, a, attrs));
52:     }
53: 
54:     private void registerAlgorithms() {
55:         ps("Signature", "MD5andSHA1withRSA",
56:             "sun.security.ssl.RSASignature", null, null);
57: 
58:         ps("KeyManagerFactory", "SunX509",
59:             "sun.security.ssl.KeyManagerFactoryImpl$SunX509", null, null);
60:         ps("KeyManagerFactory", "NewSunX509",
61:             "sun.security.ssl.KeyManagerFactoryImpl$X509",
62:             List.of("PKIX"), null);
63: 
64:         ps("TrustManagerFactory", "SunX509",
65:             "sun.security.ssl.TrustManagerFactoryImpl$SimpleFactory",
66:             null, null);
67:         ps("TrustManagerFactory", "PKIX",
68:             "sun.security.ssl.TrustManagerFactoryImpl$PKIXFactory",
69:             List.of("SunPKIX", "X509", "X.509"), null);
70: 
71:         ps("SSLContext", "TLSv1",
72:             "sun.security.ssl.SSLContextImpl$TLS10Context",
73:             List.of("SSLv3"), null);
74:         ps("SSLContext", "TLSv1.1",
75:             "sun.security.ssl.SSLContextImpl$TLS11Context", null, null);
76:         ps("SSLContext", "TLSv1.2",
77:             "sun.security.ssl.SSLContextImpl$TLS12Context", null, null);
78:         ps("SSLContext", "TLSv1.3",
79:             "sun.security.ssl.SSLContextImpl$TLS13Context", null, null);
80:         ps("SSLContext", "TLS",
81:             "sun.security.ssl.SSLContextImpl$TLSContext",
82:             List.of("SSL"), null);
83: 
84:         ps("SSLContext", "DTLSv1.0",
85:             "sun.security.ssl.SSLContextImpl$DTLS10Context", null, null);
86:         ps("SSLContext", "DTLSv1.2",
87:             "sun.security.ssl.SSLContextImpl$DTLS12Context", null, null);
88:         ps("SSLContext", "DTLS",
89:             "sun.security.ssl.SSLContextImpl$DTLSContext", null, null);
90: 
91:         ps("SSLContext", "Default",
92:             "sun.security.ssl.SSLContextImpl$DefaultSSLContext", null, null);
93: 
94:         /*
95:          * KeyStore
96:          */
97:         ps("KeyStore", "PKCS12",
98:             "sun.security.pkcs12.PKCS12KeyStore", null, null);
99:     }
100: }
